      setData(json)
      setError(null)
      setLastRefresh(new Date())
      setCountdown(30)
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Failed to fetch')
    } finally {
      setLoading(false)
    }
  }, [])

